"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["46395"],{61639(i){i.exports=JSON.parse('{"tag":{"label":"gamedev","permalink":"/sysanalyst-kb.github.io/docs/tags/gamedev","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":11,"items":[{"id":"specialization/gamedev-analytics","title":"Game Analytics","description":"Game Analytics \u2014 \u0444\u0443\u043D\u0434\u0430\u043C\u0435\u043D\u0442 \u0432\u0441\u0435\u0445 \u0440\u0435\u0448\u0435\u043D\u0438\u0439 \u0432 \u0438\u0433\u0440\u0430\u0445. \u0422\u0440\u0435\u043A\u0438\u043D\u0433 \u0441\u043E\u0431\u044B\u0442\u0438\u0439 (event tracking), \u043F\u043E\u0441\u0442\u0440\u043E\u0435\u043D\u0438\u0435 \u0432\u043E\u0440\u043E\u043D\u043E\u043A (funnel), \u0430\u043D\u0430\u043B\u0438\u0437 \u043C\u0435\u0442\u0440\u0438\u043A (retention, ARPU, LTV) \u0438 A/B \u0442\u0435\u0441\u0442\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0445\u0435\u043C\u0443 \u0441\u043E\u0431\u044B\u0442\u0438\u0439, \u0434\u0430\u0448\u0431\u043E\u0440\u0434\u044B \u0438 \u043F\u0430\u0439\u043F\u043B\u0430\u0439\u043D \u0434\u0430\u043D\u043D\u044B\u0445 (\u043A\u043B\u0438\u0435\u043D\u0442 \u2192 \u0441\u0435\u0440\u0432\u0435\u0440 \u2192 DWH \u2192 BI). \u0411\u0435\u0437 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0438 \u0438\u0433\u0440\u044B \u0441\u043B\u0435\u043F\u044B: \u043D\u0435\u043B\u044C\u0437\u044F \u043F\u043E\u043D\u044F\u0442\u044C, \u043F\u043E\u0447\u0435\u043C\u0443 \u0438\u0433\u0440\u043E\u043A\u0438 \u0443\u0445\u043E\u0434\u044F\u0442, \u0433\u0434\u0435 \u043E\u043D\u0438 \u0437\u0430\u0441\u0442\u0440\u0435\u0432\u0430\u044E\u0442 \u0438 \u0447\u0442\u043E \u043F\u0440\u0438\u043D\u043E\u0441\u0438\u0442 \u0434\u0435\u043D\u044C\u0433\u0438. \u0412 GameDev \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u043D\u0435 \xab\u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0430\xbb, \u0430 \u0434\u0432\u0438\u0436\u0443\u0449\u0430\u044F \u0441\u0438\u043B\u0430 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-analytics"},{"id":"specialization/gamedev-path","title":"GameDev \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u0432 \u0433\u0435\u0439\u043C\u0434\u0435\u0432\u0435","description":"GameDev-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u2014 \u043C\u043E\u0441\u0442 \u043C\u0435\u0436\u0434\u0443 \u0433\u0435\u0439\u043C-\u0434\u0438\u0437\u0430\u0439\u043D\u0435\u0440\u0430\u043C\u0438, \u043F\u0440\u043E\u0434\u0430\u043A\u0442-\u043C\u0435\u043D\u0435\u0434\u0436\u0435\u0440\u0430\u043C\u0438 \u0438 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u043E\u0439. \u0420\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0431\u0430\u043B\u0430\u043D\u0441\u0430\u043C\u0438, \u043C\u0430\u0442\u0447\u043C\u0435\u0439\u043A\u0438\u043D\u0433\u043E\u043C, \u043C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u0435\u0439 (IAP, \u0440\u0435\u043A\u043B\u0430\u043C\u0430), LiveOps (\u0438\u0432\u0435\u043D\u0442\u044B, \u0431\u043E\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0430), \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u043C\u0438 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0430\u043C\u0438 \u0438 \u0438\u0433\u0440\u043E\u0432\u043E\u0439 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u043E\u0439. \u0412 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u043A\u043E\u0440\u043F\u043E\u0440\u0430\u0442\u0438\u0432\u043D\u043E\u0439 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438, \u0432 \u0438\u0433\u0440\u0430\u0445 \u043A\u0440\u0438\u0442\u0438\u0447\u043D\u044B: real-time \u0441\u0435\u0441\u0441\u0438\u0438, \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u044B \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439, \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \xab\u0437\u0430\u043C\u043A\u043D\u0443\u0442\u044B\u0435 \u0446\u0438\u043A\u043B\u044B\xbb \u0438 A/B-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-path"},{"id":"specialization/gamedev-gdd","title":"GDD \u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430\u0446\u0438\u044F \u0432 GameDev \u2014 \u043E\u0442 SRS \u043A Game Design Document","description":"\u0412 GameDev \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0435 \u043F\u0438\u0448\u0435\u0442 SRS \u043D\u0430 100 \u0441\u0442\u0440\u0430\u043D\u0438\u0446. \u041E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0430\u0440\u0442\u0435\u0444\u0430\u043A\u0442 \u2014 GDD (Game Design Document) \u0432 \u0446\u0435\u043D\u0442\u0440\u0435 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430 \u2014 \u0438\u0433\u0440\u043E\u0432\u043E\u0439 \u043E\u043F\u044B\u0442 \u0438 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438, \u0430 \u043D\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-gdd"},{"id":"specialization/gamedev-liveops","title":"LiveOps \u2014 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0436\u0438\u0432\u044B\u043C \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u043C","description":"LiveOps \u2014 \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0435 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438\u0433\u0440\u043E\u0439 \u043F\u043E\u0441\u043B\u0435 \u0437\u0430\u043F\u0443\u0441\u043A\u0430: \u0438\u0432\u0435\u043D\u0442\u044B, \u0431\u043E\u0435\u0432\u044B\u0435 \u043F\u0440\u043E\u043F\u0443\u0441\u043A\u0438 (Battle Pass), \u0435\u0436\u0435\u0434\u043D\u0435\u0432\u043D\u044B\u0435 \u0437\u0430\u0434\u0430\u043D\u0438\u044F, \u0441\u0435\u0437\u043E\u043D\u043D\u044B\u0439 \u043A\u043E\u043D\u0442\u0435\u043D\u0442 \u0438 \u0440\u043E\u0442\u0430\u0446\u0438\u044F \u043C\u0430\u0433\u0430\u0437\u0438\u043D\u0430. \u0426\u0435\u043B\u044C \u2014 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0440\u0435\u0441 \u0438\u0433\u0440\u043E\u043A\u043E\u0432, \u0443\u0432\u0435\u043B\u0438\u0447\u0438\u0432\u0430\u0442\u044C retention \u0438 \u0434\u043E\u0445\u043E\u0434 \u043D\u0430 \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u0438\u0438 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0438 \u043B\u0435\u0442. \u0425\u043E\u0440\u043E\u0448\u0438\u0439 LiveOps \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0438\u0433\u0440\u0443 \u0432 \xab\u0436\u0438\u0432\u043E\u0439 \u0441\u0435\u0440\u0432\u0438\u0441\xbb (Games-as-a-Service), \u0433\u0434\u0435 \u043A\u0430\u0436\u0434\u044B\u0439 \u0434\u0435\u043D\u044C \u0435\u0441\u0442\u044C \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0437\u0430\u0439\u0442\u0438. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u043A\u043E\u043D\u0442\u0435\u043D\u0442-\u043A\u0430\u043B\u0435\u043D\u0434\u0430\u0440\u044C, \u0444\u043E\u0440\u043C\u0443\u043B\u044B \u0438\u0432\u0435\u043D\u0442\u043E\u0432, \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u0438\u0445 \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 \u0438 \u0441\u0432\u044F\u0437\u044C \u0441 \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u043E\u0439 \u0438\u0433\u0440\u044B.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-liveops"},{"id":"specialization/gamedev-sdk","title":"SDK-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0432 \u0438\u0433\u0440\u0430\u0445 \u2014 Firebase, GameAnalytics, Push","description":"\u041C\u043E\u0431\u0438\u043B\u044C\u043D\u0430\u044F \u0438\u0433\u0440\u0430 \u2014 \u043D\u0435 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u043E\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u041E\u043D\u0430 \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442 5\u201310+ SDK (Analytics, Push, Crash, Monetization, Attribution). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442, \u043A\u0430\u043A\u0438\u0435 SDK \u043D\u0443\u0436\u043D\u044B, \u043A\u0430\u043A\u0438\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F \u043E\u043D\u0438 \u0448\u043B\u044E\u0442, \u043A\u0430\u043A \u0434\u0430\u043D\u043D\u044B\u0435 \u0442\u0435\u043A\u0443\u0442 \u043E\u0442 \u043A\u043B\u0438\u0435\u043D\u0442\u0430 \u0432 DWH \u0438 \u043A\u0430\u043A\u0438\u0435 \u0440\u0438\u0441\u043A\u0438 \u0443 \u043A\u0430\u0436\u0434\u043E\u0439 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438. \u0413\u043B\u0430\u0432\u043D\u043E\u0435: SDK \u2014 \u044D\u0442\u043E \u043A\u043E\u0434 \u0432 \u043A\u043B\u0438\u0435\u043D\u0442\u0435, \u0435\u0433\u043E \u043D\u0430\u0434\u043E \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C, \u043E\u0431\u043D\u043E\u0432\u043B\u044F\u0442\u044C \u0438 \u043C\u043E\u043D\u0438\u0442\u043E\u0440\u0438\u0442\u044C. \u041E\u0448\u0438\u0431\u043A\u0430 \u0432 SDK \u043C\u043E\u0436\u0435\u0442 \u0441\u0442\u043E\u0438\u0442\u044C revenue (\u043F\u043E\u0442\u0435\u0440\u044F\u043D\u043D\u044B\u0435 \u0441\u043E\u0431\u044B\u0442\u0438\u044F) \u0438\u043B\u0438 \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0430 (\u043A\u0440\u0430\u0448).","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-sdk"},{"id":"specialization/gamedev-architecture","title":"\u0410\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u0438\u0433\u0440\u043E\u0432\u044B\u0445 \u043F\u0440\u043E\u0435\u043A\u0442\u043E\u0432","description":"\u0418\u0433\u0440\u043E\u0432\u0430\u044F \u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0430 \u043F\u0440\u0438\u043D\u0446\u0438\u043F\u0438\u0430\u043B\u044C\u043D\u043E \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 Enterprise. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043A\u043E\u043D\u0446\u0435\u043F\u0446\u0438\u0438: authoritative server (\u0441\u0435\u0440\u0432\u0435\u0440 \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 \u0432\u0441\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u044F), client-side prediction (\u043A\u043B\u0438\u0435\u043D\u0442 \u043F\u0440\u0435\u0434\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442, \u0447\u0442\u043E\u0431\u044B \u0441\u043A\u0440\u044B\u0442\u044C \u043B\u0430\u0433), UDP \u0432\u043C\u0435\u0441\u0442\u043E TCP (\u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C \u0432\u0430\u0436\u043D\u0435\u0435 \u043D\u0430\u0434\u0451\u0436\u043D\u043E\u0441\u0442\u0438), Entity-Component pattern, state synchronization \u0438 rollback netcode \u0434\u043B\u044F fighting/RTS \u0438\u0433\u0440. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u043F\u043E\u043D\u0438\u043C\u0430\u0442\u044C \u044D\u0442\u0438 \u043F\u0430\u0442\u0442\u0435\u0440\u043D\u044B, \u0447\u0442\u043E\u0431\u044B \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C API \u0438\u0433\u0440\u043E\u0432\u043E\u0433\u043E \u0431\u044D\u043A\u0435\u043D\u0434\u0430 \u0438 \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-architecture"},{"id":"specialization/gamedev-economy","title":"\u0418\u0433\u0440\u043E\u0432\u0430\u044F \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u0430 \u0438 \u0431\u0430\u043B\u0430\u043D\u0441","description":"\u0418\u0433\u0440\u043E\u0432\u0430\u044F \u044D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u0430 \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0440\u0435\u0441\u0443\u0440\u0441\u043E\u0432 \u0438 \u0432\u0430\u043B\u044E\u0442, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0433\u0440\u043E\u043A \u0437\u0430\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 \u0438 \u0442\u0440\u0430\u0442\u0438\u0442. \u0412 F2P-\u0438\u0433\u0440\u0430\u0445 \u0434\u0432\u0430 \u0442\u0438\u043F\u0430 \u0432\u0430\u043B\u044E\u0442 \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u044C \u0431\u0430\u043B\u0430\u043D\u0441, \u043F\u0440\u0438 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0438\u0433\u0440\u0430 \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u043D\u043E\u0439 (\u0443 \u0438\u0433\u0440\u043E\u043A\u0430 \u0435\u0441\u0442\u044C \u0440\u0435\u0441\u0443\u0440\u0441\u044B \u043D\u0430 \u043F\u0440\u043E\u0433\u0440\u0435\u0441\u0441), \u043D\u043E \u043F\u043E\u0431\u0443\u0436\u0434\u0430\u0435\u0442 \u043F\u043B\u0430\u0442\u0438\u0442\u044C (\u0440\u0435\u0441\u0443\u0440\u0441\u044B \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044E\u0442\u0441\u044F \u0432 \u043D\u0443\u0436\u043D\u044B\u0439 \u043C\u043E\u043C\u0435\u043D\u0442). \u042D\u043A\u043E\u043D\u043E\u043C\u0438\u043A\u0430 \u043C\u043E\u0434\u0435\u043B\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0432 Excel: \u0441\u043E\u0442\u043D\u0438 \u0441\u0442\u0440\u043E\u043A, \u0434\u0435\u0441\u044F\u0442\u043A\u0438 \u043B\u0438\u0441\u0442\u043E\u0432, \u0432\u0441\u0435 \u0446\u0438\u0444\u0440\u044B \u0434\u043E\u043B\u0436\u043D\u044B \u0441\u0445\u043E\u0434\u0438\u0442\u044C\u0441\u044F.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-economy"},{"id":"specialization/gamedev-matchmaking","title":"\u041C\u0430\u0442\u0447\u043C\u0435\u0439\u043A\u0438\u043D\u0433 \u0438 \u0438\u0433\u0440\u043E\u0432\u044B\u0435 \u0441\u0435\u0441\u0441\u0438\u0438","description":"\u041C\u0430\u0442\u0447\u043C\u0435\u0439\u043A\u0438\u043D\u0433 \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u043F\u043E\u0434\u0431\u043E\u0440\u0430 \u0438\u0433\u0440\u043E\u043A\u043E\u0432 \u0434\u043B\u044F PvP. \u041E\u0441\u043D\u043E\u0432\u0430 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E \u043C\u0430\u0442\u0447\u0430 (\u0442\u043E\u0447\u043D\u043E\u0441\u0442\u044C \u043F\u043E\u0434\u0431\u043E\u0440\u0430 \u043F\u043E \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0443) vs \u0432\u0440\u0435\u043C\u044F \u043E\u0436\u0438\u0434\u0430\u043D\u0438\u044F. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u043F\u043E\u0434\u0431\u043E\u0440\u0430, \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C \u0441\u0435\u0441\u0441\u0438\u0438, \u0430\u043B\u0433\u043E\u0440\u0438\u0442\u043C\u044B \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u044F \u043F\u043E\u0438\u0441\u043A\u0430 \u0438 \u0430\u043D\u0442\u0438\u0447\u0438\u0442. \u041E\u0441\u043E\u0431\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u043E\u0442\u0440\u0430\u0441\u043B\u0438: \u0440\u0435\u0448\u0435\u043D\u0438\u0435 \u0437\u0430\u0434\u0430\u0447 \u043E\u043F\u0442\u0438\u043C\u0438\u0437\u0430\u0446\u0438\u0438 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438, \u0433\u0434\u0435 \u043D\u0435\u043F\u0440\u0438\u0435\u043C\u043B\u0435\u043C\u043E \u0436\u0434\u0430\u0442\u044C \xab\u0438\u0434\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E\xbb \u0441\u043E\u043F\u0435\u0440\u043D\u0438\u043A\u0430 \u0434\u043E\u043B\u044C\u0448\u0435 10\u201330 \u0441\u0435\u043A\u0443\u043D\u0434.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-matchmaking"},{"id":"specialization/gamedev-monetization","title":"\u041C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u2014 IAP, \u0440\u0435\u043A\u043B\u0430\u043C\u0430, \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438","description":"\u041C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u0432 \u0438\u0433\u0440\u0430\u0445 \u0441\u0442\u0440\u043E\u0438\u0442\u0441\u044F \u043D\u0430 \u0442\u0440\u0451\u0445 \u043A\u0438\u0442\u0430\u0445 ARPU, ARPPU, \u043A\u043E\u043D\u0432\u0435\u0440\u0441\u0438\u044F \u0432 \u043F\u043B\u0430\u0442\u044F\u0449\u0435\u0433\u043E (1.5\u20135%), LTV. \u0426\u0435\u043B\u044C \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u0441\u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C store-\u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E, \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u044B\u0435 placements, \u0446\u0435\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u0442\u0440\u0435\u043A\u0438\u043D\u0433 \u043F\u043E\u043A\u0443\u043F\u043E\u043A \u0442\u0430\u043A, \u0447\u0442\u043E\u0431\u044B \u043C\u0430\u043A\u0441\u0438\u043C\u0438\u0437\u0438\u0440\u043E\u0432\u0430\u0442\u044C LTV \u043F\u0440\u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0438 \u0445\u043E\u0440\u043E\u0448\u0435\u0433\u043E \u0438\u0433\u0440\u043E\u0432\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430. \u0413\u043B\u0430\u0432\u043D\u043E\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u043E: \u043C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u043D\u0435 \u0434\u043E\u043B\u0436\u043D\u0430 \u043B\u043E\u043C\u0430\u0442\u044C \u0433\u0435\u0439\u043C\u043F\u043B\u0435\u0439.","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-monetization"},{"id":"specialization/gamedev-publishing","title":"\u041F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u044F \u0438\u0433\u0440\u044B \u2014 App Store, Google Play, IAP, \u0440\u0435\u0439\u0442\u0438\u043D\u0433","description":"\u041F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u044F \u0438\u0433\u0440\u044B \u0432 App Store \u0438 Google Play \u2014 \u043D\u0435 \xab\u043A\u0438\u043D\u044C \u0431\u0438\u043B\u0434 \u2014 \u0438 \u0433\u043E\u0442\u043E\u0432\u043E\xbb. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0443\u0447\u0430\u0441\u0442\u0432\u0443\u0435\u0442 \u0432 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0438 IAP-\u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432 \u0432 \u043A\u043E\u043D\u0441\u043E\u043B\u044F\u0445, \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u0432\u043E\u0437\u0440\u0430\u0441\u0442\u043D\u043E\u0433\u043E \u0440\u0435\u0439\u0442\u0438\u043D\u0433\u0430 (ESRB/PEGI), \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0435 \u043F\u0440\u0430\u0432\u0438\u043B \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B (loot boxes \u0437\u0430\u043F\u0440\u0435\u0449\u0435\u043D\u044B \u0432 \u0440\u044F\u0434\u0435 \u0441\u0442\u0440\u0430\u043D), \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0435 \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0438 \u0438 \u0430\u0442\u0440\u0438\u0431\u0443\u0446\u0438\u0438. \u0415\u0441\u043B\u0438 \u043D\u0435 \u0437\u043D\u0430\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B \u2014 \u0438\u0433\u0440\u0443 \u043C\u043E\u0433\u0443\u0442 \u043E\u0442\u043A\u043B\u043E\u043D\u0438\u0442\u044C \u043D\u0430 \u0440\u0435\u0432\u044C\u044E \u0438\u043B\u0438 \u0437\u0430\u0431\u0430\u043D\u0438\u0442\u044C \u043F\u043E\u0441\u043B\u0435 \u0440\u0435\u043B\u0438\u0437\u0430. \u041F\u043E\u0442\u0435\u0440\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u043D\u0430 \u0440\u0435\u0432\u044C\u044E: 1\u20137 \u0434\u043D\u0435\u0439 (App Store) / 1\u20133 \u0447\u0430\u0441\u0430 (Google Play).","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-publishing"},{"id":"specialization/gamedev-social","title":"\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438 \u0438 \u0434\u0440\u0443\u0437\u044C\u044F","description":"\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438 \u2014 \u043A\u043B\u044E\u0447\u0435\u0432\u043E\u0439 \u0434\u0440\u0430\u0439\u0432\u0435\u0440 retention \u0438 \u0432\u0438\u0440\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0432 \u0438\u0433\u0440\u0430\u0445. \u0414\u0440\u0443\u0437\u044C\u044F, \u043A\u043B\u0430\u043D\u044B/\u0433\u0438\u043B\u044C\u0434\u0438\u0438, \u0447\u0430\u0442, PvP-\u043B\u0438\u0433\u0438, \u0442\u0443\u0440\u043D\u0438\u0440\u044B \u0438 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0430 \u043F\u0440\u0438\u0433\u043B\u0430\u0448\u0435\u043D\u0438\u0439 \u043F\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u044E\u0442 \u043E\u0434\u0438\u043D\u043E\u0447\u043D\u0443\u044E \u0438\u0433\u0440\u0443 \u0432 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439 \u043E\u043F\u044B\u0442. \u0418\u0433\u0440\u043E\u043A\u0438, \u0443 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0435\u0441\u0442\u044C \u0434\u0440\u0443\u0437\u044C\u044F \u0432 \u0438\u0433\u0440\u0435, \u043F\u043E\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 retention D30 \u043D\u0430 30\u201350% \u0432\u044B\u0448\u0435, \u0447\u0435\u043C \u043E\u0434\u0438\u043D\u043E\u0447\u043A\u0438. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439 \u0433\u0440\u0430\u0444, \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u043F\u0440\u0438\u0433\u043B\u0430\u0448\u0435\u043D\u0438\u0439 (invite), \u0441\u043E\u0432\u043C\u0435\u0441\u0442\u043D\u044B\u0435 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u0438 (co-op \u0440\u0435\u0439\u0434\u044B, \u0432\u0435\u0447\u0435\u0440\u0438\u043D\u043A\u0438) \u0438 \u043C\u0435\u0445\u0430\u043D\u0438\u0437\u043C\u044B \u0432\u0438\u0440\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0440\u043E\u0441\u0442\u0430 (share, invite, gifting).","permalink":"/sysanalyst-kb.github.io/docs/specialization/gamedev-social"}],"unlisted":false}}')}}]);